import React from "react";
import styles from "../styles/TaskList.module.css";

const TaskList = ({ tasks, onDelete, onEdit, onToggleStatus }) => {
  return (
    <div className={styles.list}>
      {tasks.length === 0 ? (
        <p style={{ textAlign: "center", color: "var(--text-secondary)", padding: "30px", margin: 0 }}>
          No hay tareas en esta vista.
        </p>
      ) : (
        tasks.map((task) => (
          <div key={task.id} className={styles.taskItem}>

            <button 
              className={`${styles.checkbox} ${task.status === "COMPLETADA" ? styles.completed : ""}`}
              onClick={() => onToggleStatus(task)}
            >
              <div className={styles.checkboxInner}></div>
            </button>

            <div className={styles.content}>
              <h3 className={`${styles.title} ${task.status === "COMPLETADA" ? styles.completed : ""}`}>
                {task.title}
              </h3>
              {task.description && (
                <p className={styles.description}>{task.description}</p>
              )}
              <div className={styles.meta}>
                {task.deadline && (
                  <span className={styles.deadline}>
                    {new Date(task.deadline).toLocaleString([], {hour: '2-digit', minute:'2-digit', day: '2-digit', month: 'short'})}
                  </span>
                )}
                {task.priority === "ALTA" && <span className={styles.priority}>¡Urgente!</span>}
              </div>
              <div className={styles.actions}>
                <button className={`${styles.actionBtn} ${styles.editBtn}`} onClick={() => onEdit(task)}>
                  Editar
                </button>
                <button 
                  className={`${styles.actionBtn} ${styles.deleteBtn}`} 
                  onClick={() => {
                    if(window.confirm("¿Seguro que quieres borrar esta tarea?")) onDelete(task.id);
                  }}
                >
                  Borrar
                </button>
              </div>
            </div>

          </div>
        ))
      )}
    </div>
  );
};

export default TaskList;
